 = {\n  message_id: number;\n  summary: string;\n  character_operations?: CharacterOperation[];\n  item_operations?: ItemOperation[];\n  current_info_update?: CurrentInfoUpdate | null;\n  updated_at: string;\n};\n\nfunction getAssistantMessage(message_id: number): ChatMessage | null {\n  const message = window.TavernHelper.getChatMessages(message_id, { include_swipes: false })[0];\n  if (!message) {\n    console.info('[CosmosMemory] 未找到消息楼层', { message_id });\n    return null;\n  }\n\n  if (message.role !== 'assistant') {\n    console.info('[CosmosMemory] 跳过非 assistant 消息', { message_id, role: message.role });\n    return null;\n  }\n\n  console.info('[CosmosMemory] 获取到 assistant 消息', {\n    message_id,\n    content_length: message.message.length,\n    is_hidden: message.is_hidden,\n  });\n  return message;\n}\n\nfunction getRegexedAiContent(message: ChatMessage): string {\n  const regexed_content = window.TavernHelper.formatAsTavernRegexedString(message.message, 'ai_output', 'prompt', {\n    depth: 0,\n  }).trim();\n\n  console.info('[CosmosMemory] 完成酒馆正则过滤', {\n    message_id: message.message_id,\n    original_length: message.message.length,\n    regexed_length: regexed_content.length,\n  });\n\n  return regexed_content;\n}\n\nfunction saveMessageSummary(summary: MessageSummary) {\n  window.TavernHelper.updateVariablesWith(\n    variables => {\n      _.set(variables, `${SUMMARY_STORAGE_PATH}.${summary.message_id}`, summary);\n      return variables;\n    },\n    { type: 'chat' },\n  );\n  console.info('[CosmosMemory] 已写入聊天变量', {\n    path: `${SUMMARY_STORAGE_PATH}.${summary.message_id}`,\n    message_id: summary.message_id,\n  });\n}\n\nfunction getStoredSummaryIds(): Set<number> {\n  return new Set(getStoredMessageSummaries().map(summary => summary.message_id));\n}\n\nfunction getMissingAssistantMessageIds(): number[] {\n  const stored_summary_ids = getStoredSummaryIds();\n  return window.TavernHelper.getChatMessages('0-{{lastMessageId}}', {\n    role: 'assistant',\n    include_swipes: false,\n  })\n    .filter(message => !stored_summary_ids.has(message.message_id))\n    .map(message => message.message_id);\n}\n\nexport function getStoredMessageSummaries(): MessageSummary[] {\n  const variables = window.TavernHelper.getVariables({ type: 'chat' });\n  const summaries = _.get(variables, SUMMARY_STORAGE_PATH, {}) as Record<string, MessageSummary>;\n\n  return Object.values(summaries)\n    .filter((summary): summary is MessageSummary => {\n      return (\n        typeof summary === 'object' &&\n        summary !== null &&\n        typeof summary.message_id === 'number' &&\n        typeof summary.summary === 'string'\n      );\n    })\n    .map(summary => {\n      const character_operations = CharacterOperationsResponse.safeParse(summary.character_operations);\n      const item_operations = ItemOperationsResponse.safeParse(summary.item_operations);\n      const current_info_update = CurrentInfoUpdateResponse.nullable().optional().safeParse(\n        summary.current_info_update,\n      );\n      return {\n        ...summary,\n        character_operations: character_operations.success ? character_operations.data : [],\n        item_operations: item_operations.success ? item_operations.data : [],\n        current_info_update: current_info_update.success ? current_info_update.data : null,\n      };\n    })\n    .sort((left, right) => left.message_id - right.message_id);\n}\n\nexport function pruneMessageSummariesAfterMessage(message_id: number): MessageSummary[] {\n  const removed_summaries: MessageSummary[] = [];\n\n  window.TavernHelper.updateVariablesWith(\n    variables => {\n      const summaries = _.get(variables, SUMMARY_STORAGE_PATH, {}) as Record<string, MessageSummary>;\n      for (const [key, summary] of Object.entries(summaries)) {\n        if (\n          typeof summary === 'object' &&\n          summary !== null &&\n          typeof summary.message_id === 'number' &&\n          summary.message_id > message_id\n        ) {\n          removed_summaries.push(summary);\n          _.unset(variables, `${SUMMARY_STORAGE_PATH}.${key}`);\n        }\n      }\n\n      return variables;\n    },\n    { type: 'chat' },\n  );\n\n  if (removed_summaries.length > 0) {\n    console.info('[CosmosMemory] 已清理高于当前发送楼层的悬空总结', {\n      current_message_id: message_id,\n      removed_message_ids: removed_summaries.map(summary => summary.message_id),\n    });\n    rebuildStoredCharactersFromSummaries(getStoredMessageSummaries());\n    rebuildStoredItemsFromSummaries(getStoredMessageSummaries());\n    rebuildStoredCurrentInfoFromSummaries(getStoredMessageSummaries());\n  }\n\n  return removed_summaries.sort((left, right) => left.message_id - right.message_id);\n}\n\nasync function summarizeReceivedMessageCore(message_id: number): Promise<MessageSummary | null> {\n  const message = getAssistantMessage(message_id);\n  if (!message) {\n    return null;\n  }\n\n  const source = getRegexedAiContent(message);\n  if (!source) {\n    console.info('[CosmosMemory] 正则过滤后的内容为空，跳过总结', { message_id });\n    return null;\n  }\n\n  const { settings } = useSettingsStore();\n  console.info('[CosmosMemory] 开始请求 AI 总结', {\n    message_id,\n    use_tavern_api: settings.ai.use_tavern_api,\n    custom_api_url: settings.ai.use_tavern_api ? undefined : settings.ai.custom_api_url,\n    selected_model: settings.ai.use_tavern_api ? undefined : settings.ai.selected_model,\n    characters_enabled: settings.characters.enabled,\n    items_enabled: settings.items.enabled,\n    current_info_enabled: settings.current_info.enabled,\n  });\n  const result = await summarizeMessage(settings.ai, source, {\n    characters_enabled: settings.characters.enabled,\n    stored_characters: settings.characters.enabled ? getStoredCharacters() : [],\n    items_enabled: settings.items.enabled,\n    stored_items: settings.items.enabled ? getStoredItems() : [],\n    current_info_enabled: settings.current_info.enabled,\n    current_info: settings.current_info.enabled ? getStoredCurrentInfo() : undefined,\n  });\n  const summary: MessageSummary = {\n    message_id,\n    summary: result.summary,\n    character_operations: settings.characters.enabled ? result.characters : [],\n    item_operations: settings.items.enabled ? result.item_operations : [],\n    current_info_update: settings.current_info.enabled ? (result.current_info_update ?? null) : null,\n    updated_at: new Date().toISOString(),\n  };\n\n  saveMessageSummary(summary);\n  if (settings.characters.enabled && summary.character_operations && summary.character_operations.length > 0) {\n    applyCharacterOperations(summary.character_operations);\n  }\n  if (settings.items.enabled && summary.item_operations && summary.item_operations.length > 0) {\n    applyItemOperations(summary.item_operations);\n  }\n  if (settings.current_info.enabled) {\n    applyCurrentInfoUpdate(summary.current_info_update);\n  }\n  return summary;\n}\n\nexport function summarizeReceivedMessage(message_id: number): Promise<MessageSummary | null> {\n  const existing_task = summarizing_messages.get(message_id);\n  if (existing_task) {\n    console.info('[CosmosMemory] 复用正在进行的楼层总结任务', { message_id });\n    return existing_task;\n  }\n\n  const task = summarizeReceivedMessageCore(message_id).finally(() => {\n    summarizing_messages.delete(message_id);\n  });\n\n  summarizing_messages.set(message_id, task);\n  return task;\n}\n\nexport async function summarizeMissingAssistantMessages(): Promise<MessageSummary[]> {\n  const message_ids = getMissingAssistantMessageIds();\n  if (message_ids.length === 0) {\n    console.info('[CosmosMemory] 发送前检查完成，没有缺失总结的 assistant 楼层');\n    return [];\n  }\n\n  console.info('[CosmosMemory] 发送前发现缺失总结的 assistant 楼层，开始依次补全', {\n    message_ids,\n    count: message_ids.length,\n  });\n\n  const summaries: MessageSummary[] = [];\n  for (const message_id of message_ids) {\n    console.info('[CosmosMemory] 发送前补全楼层总结', { message_id });\n    const summary = await summarizeReceivedMessage(message_id);\n    if (summary) {\n      summaries.push(summary);\n    }\n  }\n\n  console.info('[CosmosMemory] 发送前缺失总结补全完成', {\n    requested_count: message_ids.length,\n    summarized_count: summaries.length,\n  });\n\n  return summaries;\n}\n","import { getStoredMessageSummaries, type MessageSummary } from '@/core/summary';\nimport { useSettingsStore } from '@/store/settings';\n\nconst SUMMARY_PROMPT_ID_PREFIX = 'cosmos_memory_summary_';\nconst MESSAGE_DATA_PATH = 'cosmos_memory';\nconst HIDDEN_BY_COMPRESSION_PATH = `${MESSAGE_DATA_PATH}.hidden_by_compression`;\n\nlet injected_summary_prompt_ids: string[] = [];\n\ntype CompressionResult = {\n  hidden_message_ids: number[];\n  restored_message_ids: number[];\n  injected_summary_ids: number[];\n  skipped_without_summary_ids: number[];\n};\n\nfunction isCosmosMemoryMessage(message: ChatMessage): boolean {\n  return _.get(message.data, `${MESSAGE_DATA_PATH}.kind`) === 'summary';\n}\n\nfunction isHiddenByCompression(message: ChatMessage): boolean {\n  return _.get(message.data, HIDDEN_BY_COMPRESSION_PATH) === true;\n}\n\nfunction cloneMessageData(message: ChatMessage): Record<string, any> {\n  return _.cloneDeep(message.data ?? {});\n}\n\nfunction getOriginalAssistantMessages(): ChatMessage[] {\n  return window.TavernHelper.getChatMessages('0-{{lastMessageId}}', {\n    role: 'assistant',\n    include_swipes: false,\n  }).filter(message => !isCosmosMemoryMessage(message));\n}\n\nfunction getSummaryByMessageId(): Map<number, MessageSummary> {\n  return new Map(getStoredMessageSummaries().map(summary => [summary.message_id, summary]));\n}\n\nfunction getRetainedOriginalAssistantCount(): number {\n  const { settings } = useSettingsStore();\n  const count = settings.compression.retained_original_assistant_messages;\n  return Number.isFinite(count) ? Math.max(0, Math.floor(count)) : 5;\n}\n\nfunction clearInjectedSummaryPrompts() {\n  if (injected_summary_prompt_ids.length === 0) {\n    return;\n  }\n\n  window.TavernHelper.uninjectPrompts(injected_summary_prompt_ids);\n  injected_summary_prompt_ids = [];\n}\n\nfunction buildSummaryPromptContent(summary: MessageSummary): string {\n  return summary.summary;\n}\n\nfunction injectSummariesForHiddenMessages(messages: ChatMessage[], summaries: Map<number, MessageSummary>): number[] {\n  clearInjectedSummaryPrompts();\n\n  const last_message_id = window.TavernHelper.getLastMessageId();\n  const prompts = messages\n    .map(message => {\n      const summary = summaries.get(message.message_id);\n      if (!summary) {\n        return null;\n      }\n\n      const id = `${SUMMARY_PROMPT_ID_PREFIX}${message.message_id}`;\n      return {\n        id,\n        position: 'in_chat' as const,\n        depth: Math.max(0, last_message_id - message.message_id),\n        role: 'assistant' as const,\n        content: buildSummaryPromptContent(summary),\n      };\n    })\n    .filter((prompt): prompt is NonNullable<typeof prompt> => prompt !== null);\n\n  if (prompts.length === 0) {\n    return [];\n  }\n\n  injected_summary_prompt_ids = prompts.map(prompt => prompt.id);\n  window.TavernHelper.injectPrompts(prompts, { once: true });\n  return messages.map(message => message.message_id);\n}\n\nexport async function applySummaryCompressionForNextGeneration(): Promise<CompressionResult> {\n  const assistant_messages = getOriginalAssistantMessages();\n  const retained_count = getRetainedOriginalAssistantCount();\n  const compressible_messages =\n    retained_count === 0 ? assistant_messages : assistant_messages.slice(0, -retained_count);\n  const summaries = getSummaryByMessageId();\n  const skipped_without_summary_ids = compressible_messages\n    .filter(message => !summaries.has(message.message_id))\n    .map(message => message.message_id);\n  const messages_to_hide = compressible_messages.filter(message => {\n    if (!summaries.has(message.message_id)) {\n      return false;\n    }\n\n    return !message.is_hidden || isHiddenByCompression(message);\n  });\n  const messages_to_hide_ids = new Set(messages_to_hide.map(message => message.message_id));\n  const updates: Array<{ message_id: number; is_hidden: boolean; data: Record<string, any> }> = [];\n  const hidden_message_ids: number[] = [];\n  const restored_message_ids: number[] = [];\n\n  for (const message of assistant_messages) {\n    const should_hide = messages_to_hide_ids.has(message.message_id);\n    if (should_hide && !message.is_hidden) {\n      const data = cloneMessageData(message);\n      _.set(data, HIDDEN_BY_COMPRESSION_PATH, true);\n      updates.push({ message_id: message.message_id, is_hidden: true, data });\n      hidden_message_ids.push(message.message_id);\n      continue;\n    }\n\n    if (!should_hide && isHiddenByCompression(message)) {\n      const data = cloneMessageData(message);\n      _.unset(data, HIDDEN_BY_COMPRESSION_PATH);\n      updates.push({ message_id: message.message_id, is_hidden: false, data });\n      restored_message_ids.push(message.message_id);\n    }\n  }\n\n  if (updates.length > 0) {\n    await window.TavernHelper.setChatMessages(updates, { refresh: 'affected' });\n  }\n\n  const injected_summary_ids = injectSummariesForHiddenMessages(messages_to_hide, summaries);\n\n  console.info('[CosmosMemory] 已应用生成前摘要压缩', {\n    retained_count,\n    assistant_count: assistant_messages.length,\n    hidden_message_ids,\n    restored_message_ids,\n    injected_summary_ids,\n    skipped_without_summary_ids,\n  });\n\n  return {\n    hidden_message_ids,\n    restored_message_ids,\n    injected_summary_ids,\n    skipped_without_summary_ids,\n  };\n}\n","import { applyCharacterPromptInjection } from '@/core/characters';\nimport { applySummaryCompressionForNextGeneration } from '@/core/compression';\nimport { applyItemPromptInjection } from '@/core/items';\nimport {\n  pruneMessageSummariesAfterMessage,\n  summarizeMissingAssistantMessages,\n  summarizeReceivedMessage,\n} from '@/core/summary';\nimport { applyCurrentInfoPromptInjection } from '@/core/current-info';\nimport { useSettingsStore } from '@/store/settings';\nimport { event_types, eventSource } from '@sillytavern/script';\n\nconst SUMMARIZABLE_MESSAGE_TYPES = new Set([\n  'normal',\n  'regenerate',\n  'swipe',\n  'append',\n  'appendFinal',\n  'continue',\n  'first_message',\n]);\n\nconst SKIPPED_COMPRESSION_GENERATION_TYPES = new Set(['quiet']);\n\nlet is_summary_listener_registered = false;\n\nfunction handleMessageReceived(message_id: number, type: string) {\n  console.info('[CosmosMemory] 收到 MESSAGE_RECEIVED 事件', { message_id, type });\n\n  if (!SUMMARIZABLE_MESSAGE_TYPES.has(type)) {\n    console.info('[CosmosMemory] 跳过不可总结的消息类型', { message_id, type });\n    return;\n  }\n\n  console.info('[CosmosMemory] 开始处理楼层总结', { message_id, type });\n  void summarizeReceivedMessage(message_id)\n    .then(summary => {\n      if (!summary) {\n        console.info('[CosmosMemory] 楼层没有生成总结，可能不是 assistant 消息或过滤后为空', { message_id });\n        return;\n      }\n\n      console.info('[CosmosMemory] 楼层总结完成', {\n        message_id: summary.message_id,\n        summary_length: summary.summary.length,\n        character_operation_count: summary.character_operations?.length ?? 0,\n        item_operation_count: summary.item_operations?.length ?? 0,\n        current_info_updated: Boolean(\n          summary.current_info_update?.current_time ||\n            summary.current_info_update?.location ||\n            Object.keys(summary.current_info_update?.characters ?? {}).length > 0,\n        ),\n      });\n    })\n    .catch(error => {\n      const message = error instanceof Error ? error.message : String(error);\n      console.error('[CosmosMemory] 剧情总结失败', error);\n      toastr.error(message, 'Cosmos Memory 剧情总结失败');\n    });\n}\n\nasync function handleMessageSent(message_id: number) {\n  try {\n    console.info('[CosmosMemory] 收到 MESSAGE_SENT 事件，发送前清理悬空总结并检查缺失总结', { message_id });\n    const removed_summaries = pruneMessageSummariesAfterMessage(message_id);\n    if (removed_summaries.length > 0) {\n      console.info('[CosmosMemory] 发送前已清理悬空总结', {\n        trigger_message_id: message_id,\n        removed_message_ids: removed_summaries.map(summary => summary.message_id),\n      });\n    }\n\n    const summaries = await summarizeMissingAssistantMessages();\n    if (summaries.length > 0) {\n      console.info('[CosmosMemory] 发送前已补全缺失总结', {\n        trigger_message_id: message_id,\n        summarized_message_ids: summaries.map(summary => summary.message_id),\n      });\n    }\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    console.error('[CosmosMemory] 发送前补全剧情总结失败', error);\n    toastr.error(message, 'Cosmos Memory 发送前补全总结失败');\n    throw error;\n  }\n}\n\nasync function handleGenerationAfterCommands(\n  type: string,\n  option: {\n    quiet_prompt?: string;\n  },\n  dry_run: boolean,\n) {\n  if (dry_run || SKIPPED_COMPRESSION_GENERATION_TYPES.has(type) || option.quiet_prompt) {\n    return;\n  }\n\n  try {\n    const { settings } = useSettingsStore();\n    await applySummaryCompressionForNextGeneration();\n    applyCurrentInfoPromptInjection(settings.current_info.enabled);\n    applyItemPromptInjection(settings.items.enabled);\n    applyCharacterPromptInjection(settings.characters.enabled);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    console.error('[CosmosMemory] 生成前应用记忆注入失败', error);\n    toastr.error(message, 'Cosmos Memory 生成前记忆注入失败');\n    throw error;\n  }\n}\n\nexport function registerSummaryEvents() {\n  if (is_summary_listener_registered) {\n    console.info('[CosmosMemory] 剧情总结监听已注册，跳过重复注册');\n    return;\n  }\n\n  console.info('[CosmosMemory] 注册 MESSAGE_RECEIVED / MESSAGE_SENT / GENERATION_AFTER_COMMANDS 剧情总结监听');\n  eventSource.on(event_types.MESSAGE_RECEIVED, handleMessageReceived);\n  eventSource.on(event_types.MESSAGE_SENT, handleMessageSent);\n  eventSource.on(event_types.GENERATION_AFTER_COMMANDS, handleGenerationAfterCommands);\n  is_summary_listener_registered = true;\n}\n","import { extractCharactersFromChatContent } from '@/api/ai';\nimport { replaceStoredCharacters, type StoredCharacter } from '@/core/characters';\nimport type { AiSettings } from '@/type/settings';\n\nconst MESSAGE_DATA_PATH = 'cosmos_memory';\n\nfunction isCosmosMemoryMessage(message: ChatMessage): boolean {\n  return _.get(message.data, `${MESSAGE_DATA_PATH}.kind`) === 'summary';\n}\n\nfunction getAssistantChatContent(): string {\n  const messages = window.TavernHelper.getChatMessages('0-{{lastMessageId}}', {\n    role: 'assistant',\n    include_swipes: false,\n  })\n    .filter(message => !isCosmosMemoryMessage(message))\n    .map(message => {\n      const content = message.message.trim();\n      if (!content) {\n        return '';\n      }\n\n      return `楼层 #${message.message_id}\\n${content}`;\n    })\n    .filter(Boolean);\n\n  return messages.join('\\n\\n---\\n\\n');\n}\n\nexport async function regenerateCharactersFromChat(settings: AiSettings): Promise<StoredCharacter[]> {\n  const content = getAssistantChatContent();\n  if (!content) {\n    throw new Error('当前聊天没有可用于生成人物信息的 AI 回复。');\n  }\n\n  const characters = await extractCharactersFromChatContent(settings, content);\n  return replaceStoredCharacters(characters);\n}\n","<template>\n  <div class=\"cosmos-memory-settings\">\n    <div class=\"inline-drawer\">\n      <div class=\"inline-drawer-toggle inline-drawer-header\">\n        <b>{{ t`Cosmos Memory` }}</b>\n        <div class=\"inline-drawer-icon fa-solid fa-circle-chevron-down down\"></div>\n      </div>\n      <div class=\"inline-drawer-content\">\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"API设置\">{{ t`API设置` }}</strong>\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input id=\"cosmos_memory_use_tavern_api\" v-model=\"settings.ai.use_tavern_api\" type=\"checkbox\" />\n          <label for=\"cosmos_memory_use_tavern_api\">{{ t`是否使用酒馆API` }}</label>\n        </div>\n\n        <div v-if=\"settings.ai.use_tavern_api\" class=\"cosmos-memory-hint\">\n          {{ t`将使用 SillyTavern 当前启用的 API 设置。` }}\n        </div>\n\n        <template v-else>\n          <label class=\"cosmos-memory-field\">\n            <span>{{ t`自定义端点` }}</span>\n            <input\n              v-model.trim=\"settings.ai.custom_api_url\"\n              class=\"text_pole\"\n              type=\"url\"\n              placeholder=\"https://api.deepseek.com/v1\"\n            />\n          </label>\n\n          <label class=\"cosmos-memory-field\">\n            <span>{{ t`密钥` }}</span>\n            <input v-model.trim=\"settings.ai.custom_api_key\" class=\"text_pole\" type=\"password\" autocomplete=\"off\" />\n          </label>\n\n          <div class=\"cosmos-memory-row flex-container\">\n            <input\n              class=\"menu_button\"\n              type=\"button\"\n              :value=\"is_fetching_models ? t`获取中...` : t`获取模型列表`\"\n              :disabled=\"is_fetching_models || !settings.ai.custom_api_url.trim()\"\n              @click=\"handle_fetch_models\"\n            />\n          </div>\n\n          <label class=\"cosmos-memory-field\">\n            <span>{{ t`模型` }}</span>\n            <select v-model=\"settings.ai.selected_model\" class=\"text_pole\" :disabled=\"model_options.length === 0\">\n              <option value=\"\">{{ t`请选择模型` }}</option>\n              <option v-for=\"model in model_options\" :key=\"model\" :value=\"model\">\n                {{ model }}\n              </option>\n            </select>\n          </label>\n        </template>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input\n            class=\"menu_button\"\n            type=\"button\"\n            :value=\"is_testing ? t`测试中...` : t`发送测试消息`\"\n            :disabled=\"is_test_disabled\"\n            @click=\"handle_send_test_message\"\n          />\n        </div>\n\n        <div\n          v-if=\"test_result\"\n          class=\"cosmos-memory-test-result\"\n          :class=\"`cosmos-memory-test-result--${test_result.type}`\"\n        >\n          {{ test_result.message }}\n        </div>\n\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"总结\">{{ t`总结` }}</strong>\n        </div>\n\n        <label class=\"cosmos-memory-field\">\n          <span>{{ t`保留原文的数量` }}</span>\n          <input\n            v-model.number=\"settings.compression.retained_original_assistant_messages\"\n            class=\"text_pole\"\n            type=\"number\"\n            min=\"0\"\n            step=\"1\"\n            @change=\"normalize_retained_original_count\"\n          />\n        </label>\n\n        <div class=\"cosmos-memory-hint\">\n          {{ t`当 AI 回复数量超过该值时，旧回复会被隐藏，并在生成时用已保存的摘要替代。` }}\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input class=\"menu_button\" type=\"button\" :value=\"t`查看已有总结`\" @click=\"handle_show_summaries\" />\n        </div>\n\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"当前信息\">{{ t`当前信息` }}</strong>\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input id=\"cosmos_memory_current_info_enabled\" v-model=\"settings.current_info.enabled\" type=\"checkbox\" />\n          <label for=\"cosmos_memory_current_info_enabled\">{{ t`当前信息` }}</label>\n        </div>\n\n        <div class=\"cosmos-memory-hint\">\n          {{ t`开启后会在总结时维护当前时间、地点和角色状态，并注入到人物信息上方。` }}\n        </div>\n\n        <div class=\"cosmos-memory-current-info\">\n          <div class=\"cosmos-memory-row flex-container\">\n            <span>{{ t`当前时间` }}：{{ stored_current_info.current_time || t`尚未记录` }}</span>\n            <input class=\"menu_button\" type=\"button\" :value=\"t`刷新`\" @click=\"handle_refresh_current_info\" />\n          </div>\n          <div class=\"cosmos-memory-row flex-container\">\n            <span>{{ t`当前地点` }}：{{ stored_current_info.location || t`尚未记录` }}</span>\n          </div>\n          <div v-if=\"current_character_entries.length > 0\" class=\"cosmos-memory-current-characters\">\n            <div class=\"cosmos-memory-current-characters-title\">{{ t`当前角色列表` }}</div>\n            <dl v-for=\"[name, character] in current_character_entries\" :key=\"name\">\n              <dt>{{ name }}</dt>\n              <dd v-if=\"character.clothing\">{{ t`角色服装` }}：{{ character.clothing }}</dd>\n              <dd v-if=\"character.status\">{{ t`角色状态` }}：{{ character.status }}</dd>\n            </dl>\n          </div>\n        </div>\n\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"物品\">{{ t`物品` }}</strong>\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input id=\"cosmos_memory_items_enabled\" v-model=\"settings.items.enabled\" type=\"checkbox\" />\n          <label for=\"cosmos_memory_items_enabled\">{{ t`物品信息` }}</label>\n        </div>\n\n        <div class=\"cosmos-memory-hint\">\n          {{ t`开启后会在总结时记录影响剧情的重要道具，并注入到人物信息上方。` }}\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input class=\"menu_button\" type=\"button\" :value=\"t`查看物品信息`\" @click=\"handle_show_items\" />\n        </div>\n\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"人物\">{{ t`人物` }}</strong>\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input id=\"cosmos_memory_characters_enabled\" v-model=\"settings.characters.enabled\" type=\"checkbox\" />\n          <label for=\"cosmos_memory_characters_enabled\">{{ t`人物信息` }}</label>\n        </div>\n\n        <div class=\"cosmos-memory-hint\">\n          {{ t`开启后会在总结时提取主要角色和会重复出现的次要角色，并注入到后续提示词中。` }}\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input class=\"menu_button\" type=\"button\" :value=\"t`查看人物信息`\" @click=\"handle_show_characters\" />\n          <input\n            class=\"menu_button\"\n            type=\"button\"\n            :value=\"is_regenerating_characters ? t`重新生成中...` : t`重新生成`\"\n            :disabled=\"is_regenerate_characters_disabled\"\n            @click=\"handle_regenerate_characters\"\n          />\n        </div>\n\n        <hr class=\"sysHR\" />\n      </div>\n    </div>\n\n    <dialog ref=\"summary_dialog\" class=\"cosmos-memory-dialog\">\n      <div class=\"cosmos-memory-dialog-header\">\n        <b>{{ t`当前聊天总结` }}</b>\n        <button class=\"menu_button\" type=\"button\" @click=\"handle_close_summaries\">{{ t`关闭` }}</button>\n      </div>\n\n      <div v-if=\"stored_summaries.length === 0\" class=\"cosmos-memory-empty\">\n        {{ t`当前聊天记录还没有总结。` }}\n      </div>\n\n      <div v-else class=\"cosmos-memory-summary-list\">\n        <article v-for=\"summary in stored_summaries\" :key=\"summary.message_id\" class=\"cosmos-memory-summary-item\">\n          <div class=\"cosmos-memory-summary-meta\">\n            <b>{{ t`楼层` }} #{{ summary.message_id }}</b>\n            <span>{{ format_time(summary.updated_at) }}</span>\n          </div>\n          <p>{{ summary.summary }}</p>\n        </article>\n      </div>\n    </dialog>\n\n    <dialog ref=\"item_dialog\" class=\"cosmos-memory-dialog\">\n      <div class=\"cosmos-memory-dialog-header\">\n        <b>{{ t`当前聊天物品信息` }}</b>\n        <button class=\"menu_button\" type=\"button\" @click=\"handle_close_items\">{{ t`关闭` }}</button>\n      </div>\n\n      <div v-if=\"stored_items.length === 0\" class=\"cosmos-memory-empty\">\n        {{ t`当前聊天记录还没有物品信息。` }}\n      </div>\n\n      <div v-else class=\"cosmos-memory-summary-list\">\n        <article v-for=\"item in stored_items\" :key=\"item.name\" class=\"cosmos-memory-summary-item\">\n          <div class=\"cosmos-memory-summary-meta\">\n            <b>{{ item.name }}</b>\n          </div>\n          <p>{{ item.brief }}</p>\n        </article>\n      </div>\n    </dialog>\n\n    <dialog ref=\"character_dialog\" class=\"cosmos-memory-dialog\">\n      <div class=\"cosmos-memory-dialog-header\">\n        <b>{{ t`当前聊天人物信息` }}</b>\n        <button class=\"menu_button\" type=\"button\" @click=\"handle_close_characters\">{{ t`关闭` }}</button>\n      </div>\n\n      <div v-if=\"stored_characters.length === 0\" class=\"cosmos-memory-empty\">\n        {{ t`当前聊天记录还没有人物信息。` }}\n      </div>\n\n      <div v-else class=\"cosmos-memory-summary-list\">\n        <section v-if=\"primary_characters.length > 0\">\n          <h4>{{ t`主要角色` }}</h4>\n          <article v-for=\"character in primary_characters\" :key=\"character.name\" class=\"cosmos-memory-summary-item\">\n            <div class=\"cosmos-memory-summary-meta\">\n              <b>{{ character.name }}</b>\n            </div>\n            <dl class=\"cosmos-memory-character-fields\">\n              <template v-if=\"character.background\">\n                <dt>{{ t`背景介绍` }}</dt>\n                <dd>{{ character.background }}</dd>\n              </template>\n              <template v-if=\"character.appearance\">\n                <dt>{{ t`外貌描写` }}</dt>\n                <dd>{{ character.appearance }}</dd>\n              </template>\n              <template v-if=\"character.personality\">\n                <dt>{{ t`性格描写` }}</dt>\n                <dd>{{ character.personality }}</dd>\n              </template>\n            </dl>\n          </article>\n        </section>\n\n        <section v-if=\"secondary_characters.length > 0\">\n          <h4>{{ t`次要角色` }}</h4>\n          <article v-for=\"character in secondary_characters\" :key=\"character.name\" class=\"cosmos-memory-summary-item\">\n            <div class=\"cosmos-memory-summary-meta\">\n              <b>{{ character.name }}</b>\n            </div>\n            <p>{{ character.brief }}</p>\n          </article>\n        </section>\n      </div>\n    </dialog>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { fetchCustomModelNames, sendPing } from '@/api/ai';\nimport { regenerateCharactersFromChat } from '@/core/character-regeneration';\nimport {\n  getStoredCharacters,\n  type PrimaryCharacter,\n  type SecondaryCharacter,\n  type StoredCharacter,\n} from '@/core/characters';\nimport { getStoredItems, type StoredItem } from '@/core/items';\nimport { getStoredMessageSummaries, type MessageSummary } from '@/core/summary';\nimport { getStoredCurrentInfo, type CurrentInfo } from '@/core/current-info';\nimport { useSettingsStore } from '@/store/settings';\nimport { storeToRefs } from 'pinia';\n\ntype TestResult = {\n  type: 'success' | 'error';\n  message: string;\n};\n\nconst { settings } = storeToRefs(useSettingsStore());\n\nconst is_fetching_models = ref(false);\nconst is_testing = ref(false);\nconst is_regenerating_characters = ref(false);\nconst test_result = ref<TestResult | null>(null);\nconst stored_summaries = ref<MessageSummary[]>([]);\nconst stored_characters = ref<StoredCharacter[]>([]);\nconst stored_items = ref<StoredItem[]>([]);\nconst stored_current_info = ref<CurrentInfo>({\n  current_time: '',\n  location: '',\n  characters: {},\n});\nconst summary_dialog = ref<HTMLDialogElement | null>(null);\nconst character_dialog = ref<HTMLDialogElement | null>(null);\nconst item_dialog = ref<HTMLDialogElement | null>(null);\n\nconst model_options = computed(() => {\n  return [...new Set([settings.value.ai.selected_model, ...settings.value.ai.available_models])]\n    .map(model => model.trim())\n    .filter(Boolean);\n});\n\nconst is_test_disabled = computed(() => {\n  if (is_testing.value) {\n    return true;\n  }\n\n  return is_ai_request_disabled.value;\n});\n\nconst is_ai_request_disabled = computed(() => {\n  if (settings.value.ai.use_tavern_api) {\n    return false;\n  }\n\n  return !settings.value.ai.custom_api_url.trim() || !settings.value.ai.selected_model.trim();\n});\n\nconst is_regenerate_characters_disabled = computed(() => {\n  return is_regenerating_characters.value || is_ai_request_disabled.value;\n});\n\nconst primary_characters = computed(() => {\n  return stored_characters.value.filter((character): character is PrimaryCharacter => character.type === 'primary');\n});\n\nconst secondary_characters = computed(() => {\n  return stored_characters.value.filter((character): character is SecondaryCharacter => character.type === 'secondary');\n});\n\nconst current_character_entries = computed(() => {\n  return Object.entries(stored_current_info.value.characters).sort(([left], [right]) => left.localeCompare(right));\n});\n\nasync function handle_fetch_models() {\n  is_fetching_models.value = true;\n  test_result.value = null;\n\n  try {\n    const models = await fetchCustomModelNames(settings.value.ai);\n    settings.value.ai.available_models = models;\n\n    if (!settings.value.ai.selected_model && models.length > 0) {\n      settings.value.ai.selected_model = models[0]!;\n    }\n\n    toastr.success(t`模型列表获取成功。`);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(message);\n    test_result.value = { type: 'error', message };\n  } finally {\n    is_fetching_models.value = false;\n  }\n}\n\nasync function handle_send_test_message() {\n  is_testing.value = true;\n  test_result.value = null;\n\n  try {\n    const response = await sendPing(settings.value.ai);\n    const message = response.trim() || t`AI 返回了空内容。`;\n    test_result.value = { type: 'success', message };\n    toastr.success(t`测试消息发送成功。`);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(message);\n    test_result.value = { type: 'error', message };\n  } finally {\n    is_testing.value = false;\n  }\n}\n\nfunction handle_show_summaries() {\n  stored_summaries.value = getStoredMessageSummaries();\n  refresh_stored_current_info();\n  summary_dialog.value?.showModal();\n}\n\nfunction handle_close_summaries() {\n  summary_dialog.value?.close();\n}\n\nfunction handle_show_characters() {\n  stored_characters.value = getStoredCharacters();\n  character_dialog.value?.showModal();\n}\n\nfunction handle_close_characters() {\n  character_dialog.value?.close();\n}\n\nfunction handle_show_items() {\n  stored_items.value = getStoredItems();\n  item_dialog.value?.showModal();\n}\n\nfunction handle_close_items() {\n  item_dialog.value?.close();\n}\n\nfunction handle_refresh_current_info() {\n  refresh_stored_current_info();\n}\n\nfunction refresh_stored_current_info() {\n  try {\n    stored_current_info.value = getStoredCurrentInfo();\n  } catch (error) {\n    console.warn('[CosmosMemory] 读取当前信息失败', error);\n    stored_current_info.value = {\n      current_time: '',\n      location: '',\n      characters: {},\n    };\n  }\n}\n\nasync function handle_regenerate_characters() {\n  is_regenerating_characters.value = true;\n\n  try {\n    stored_characters.value = await regenerateCharactersFromChat(settings.value.ai);\n    toastr.success(t`人物信息重新生成成功。`);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(message, 'Cosmos Memory');\n  } finally {\n    is_regenerating_characters.value = false;\n  }\n}\n\nfunction format_time(value: string) {\n  if (!value) {\n    return '';\n  }\n\n  const date = new Date(value);\n  if (Number.isNaN(date.getTime())) {\n    return value;\n  }\n\n  return date.toLocaleString();\n}\n\nfunction normalize_retained_original_count() {\n  const count = settings.value.compression.retained_original_assistant_messages;\n  settings.value.compression.retained_original_assistant_messages = Number.isFinite(count)\n    ? Math.max(0, Math.floor(count))\n    : 5;\n}\n</script>\n\n<style scoped>\n.cosmos-memory-row {\n  align-items: center;\n  gap: 8px;\n  margin: 8px 0;\n}\n\n.cosmos-memory-field {\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n  margin: 8px 0;\n}\n\n.cosmos-memory-field > span,\n.cosmos-memory-hint {\n  opacity: 0.85;\n}\n\n.cosmos-memory-section-title {\n  border-bottom: 1px solid var(--SmartThemeBorderColor);\n  margin: 12px 0 8px;\n  padding-bottom: 4px;\n}\n\n.cosmos-memory-current-info {\n  margin: 8px 0;\n}\n\n.cosmos-memory-current-characters {\n  margin-top: 8px;\n}\n\n.cosmos-memory-current-characters-title {\n  font-weight: 700;\n  margin-bottom: 4px;\n}\n\n.cosmos-memory-current-characters dl {\n  margin: 6px 0;\n}\n\n.cosmos-memory-current-characters dt {\n  font-weight: 700;\n}\n\n.cosmos-memory-current-characters dd {\n  margin: 2px 0 0 12px;\n  white-space: pre-wrap;\n}\n\n.cosmos-memory-test-result {\n  border-radius: 8px;\n  margin: 8px 0;\n  padding: 8px 10px;\n  white-space: pre-wrap;\n}\n\n.cosmos-memory-test-result--success {\n  background: rgba(46, 125, 50, 0.22);\n  border: 1px solid #2e7d32;\n}\n\n.cosmos-memory-test-result--error {\n  background: rgba(198, 40, 40, 0.18);\n  border: 1px solid #c62828;\n}\n\n.cosmos-memory-dialog {\n  background: var(--SmartThemeBlurTintColor);\n  border: 1px solid var(--SmartThemeBorderColor);\n  border-radius: 8px;\n  color: var(--SmartThemeBodyColor);\n  max-height: min(720px, 80vh);\n  max-width: min(720px, 90vw);\n  padding: 12px;\n  width: 720px;\n}\n\n.cosmos-memory-dialog::backdrop {\n  background: rgba(0, 0, 0, 0.45);\n}\n\n.cosmos-memory-dialog-header,\n.cosmos-memory-summary-meta {\n  align-items: center;\n  display: flex;\n  gap: 12px;\n  justify-content: space-between;\n}\n\n.cosmos-memory-empty {\n  margin-top: 12px;\n  opacity: 0.85;\n}\n\n.cosmos-memory-summary-list {\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n  margin-top: 12px;\n  overflow-y: auto;\n}\n\n.cosmos-memory-summary-item {\n  border: 1px solid var(--SmartThemeBorderColor);\n  border-radius: 8px;\n  padding: 10px;\n}\n\n.cosmos-memory-summary-item p {\n  margin: 8px 0 0;\n  white-space: pre-wrap;\n}\n\n.cosmos-memory-summary-meta span {\n  font-size: 0.9em;\n  opacity: 0.75;\n}\n\n.cosmos-memory-character-fields {\n  margin: 8px 0 0;\n}\n\n.cosmos-memory-character-fields dt {\n  font-weight: 700;\n  margin-top: 8px;\n}\n\n.cosmos-memory-character-fields dd {\n  margin: 4px 0 0;\n  white-space: pre-wrap;\n}\n</style>\n","<template>\n  <div class=\"cosmos-memory-settings\">\n    <div class=\"inline-drawer\">\n      <div class=\"inline-drawer-toggle inline-drawer-header\">\n        <b>{{ t`Cosmos Memory` }}</b>\n        <div class=\"inline-drawer-icon fa-solid fa-circle-chevron-down down\"></div>\n      </div>\n      <div class=\"inline-drawer-content\">\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"API设置\">{{ t`API设置` }}</strong>\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input id=\"cosmos_memory_use_tavern_api\" v-model=\"settings.ai.use_tavern_api\" type=\"checkbox\" />\n          <label for=\"cosmos_memory_use_tavern_api\">{{ t`是否使用酒馆API` }}</label>\n        </div>\n\n        <div v-if=\"settings.ai.use_tavern_api\" class=\"cosmos-memory-hint\">\n          {{ t`将使用 SillyTavern 当前启用的 API 设置。` }}\n        </div>\n\n        <template v-else>\n          <label class=\"cosmos-memory-field\">\n            <span>{{ t`自定义端点` }}</span>\n            <input\n              v-model.trim=\"settings.ai.custom_api_url\"\n              class=\"text_pole\"\n              type=\"url\"\n              placeholder=\"https://api.deepseek.com/v1\"\n            />\n          </label>\n\n          <label class=\"cosmos-memory-field\">\n            <span>{{ t`密钥` }}</span>\n            <input v-model.trim=\"settings.ai.custom_api_key\" class=\"text_pole\" type=\"password\" autocomplete=\"off\" />\n          </label>\n\n          <div class=\"cosmos-memory-row flex-container\">\n            <input\n              class=\"menu_button\"\n              type=\"button\"\n              :value=\"is_fetching_models ? t`获取中...` : t`获取模型列表`\"\n              :disabled=\"is_fetching_models || !settings.ai.custom_api_url.trim()\"\n              @click=\"handle_fetch_models\"\n            />\n          </div>\n\n          <label class=\"cosmos-memory-field\">\n            <span>{{ t`模型` }}</span>\n            <select v-model=\"settings.ai.selected_model\" class=\"text_pole\" :disabled=\"model_options.length === 0\">\n              <option value=\"\">{{ t`请选择模型` }}</option>\n              <option v-for=\"model in model_options\" :key=\"model\" :value=\"model\">\n                {{ model }}\n              </option>\n            </select>\n          </label>\n        </template>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input\n            class=\"menu_button\"\n            type=\"button\"\n            :value=\"is_testing ? t`测试中...` : t`发送测试消息`\"\n            :disabled=\"is_test_disabled\"\n            @click=\"handle_send_test_message\"\n          />\n        </div>\n\n        <div\n          v-if=\"test_result\"\n          class=\"cosmos-memory-test-result\"\n          :class=\"`cosmos-memory-test-result--${test_result.type}`\"\n        >\n          {{ test_result.message }}\n        </div>\n\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"总结\">{{ t`总结` }}</strong>\n        </div>\n\n        <label class=\"cosmos-memory-field\">\n          <span>{{ t`保留原文的数量` }}</span>\n          <input\n            v-model.number=\"settings.compression.retained_original_assistant_messages\"\n            class=\"text_pole\"\n            type=\"number\"\n            min=\"0\"\n            step=\"1\"\n            @change=\"normalize_retained_original_count\"\n          />\n        </label>\n\n        <div class=\"cosmos-memory-hint\">\n          {{ t`当 AI 回复数量超过该值时，旧回复会被隐藏，并在生成时用已保存的摘要替代。` }}\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input class=\"menu_button\" type=\"button\" :value=\"t`查看已有总结`\" @click=\"handle_show_summaries\" />\n        </div>\n\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"当前信息\">{{ t`当前信息` }}</strong>\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input id=\"cosmos_memory_current_info_enabled\" v-model=\"settings.current_info.enabled\" type=\"checkbox\" />\n          <label for=\"cosmos_memory_current_info_enabled\">{{ t`当前信息` }}</label>\n        </div>\n\n        <div class=\"cosmos-memory-hint\">\n          {{ t`开启后会在总结时维护当前时间、地点和角色状态，并注入到人物信息上方。` }}\n        </div>\n\n        <div class=\"cosmos-memory-current-info\">\n          <div class=\"cosmos-memory-row flex-container\">\n            <span>{{ t`当前时间` }}：{{ stored_current_info.current_time || t`尚未记录` }}</span>\n            <input class=\"menu_button\" type=\"button\" :value=\"t`刷新`\" @click=\"handle_refresh_current_info\" />\n          </div>\n          <div class=\"cosmos-memory-row flex-container\">\n            <span>{{ t`当前地点` }}：{{ stored_current_info.location || t`尚未记录` }}</span>\n          </div>\n          <div v-if=\"current_character_entries.length > 0\" class=\"cosmos-memory-current-characters\">\n            <div class=\"cosmos-memory-current-characters-title\">{{ t`当前角色列表` }}</div>\n            <dl v-for=\"[name, character] in current_character_entries\" :key=\"name\">\n              <dt>{{ name }}</dt>\n              <dd v-if=\"character.clothing\">{{ t`角色服装` }}：{{ character.clothing }}</dd>\n              <dd v-if=\"character.status\">{{ t`角色状态` }}：{{ character.status }}</dd>\n            </dl>\n          </div>\n        </div>\n\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"物品\">{{ t`物品` }}</strong>\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input id=\"cosmos_memory_items_enabled\" v-model=\"settings.items.enabled\" type=\"checkbox\" />\n          <label for=\"cosmos_memory_items_enabled\">{{ t`物品信息` }}</label>\n        </div>\n\n        <div class=\"cosmos-memory-hint\">\n          {{ t`开启后会在总结时记录影响剧情的重要道具，并注入到人物信息上方。` }}\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input class=\"menu_button\" type=\"button\" :value=\"t`查看物品信息`\" @click=\"handle_show_items\" />\n        </div>\n\n        <div class=\"cosmos-memory-section-title flex-container\">\n          <strong class=\"flex1\" data-i18n=\"人物\">{{ t`人物` }}</strong>\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input id=\"cosmos_memory_characters_enabled\" v-model=\"settings.characters.enabled\" type=\"checkbox\" />\n          <label for=\"cosmos_memory_characters_enabled\">{{ t`人物信息` }}</label>\n        </div>\n\n        <div class=\"cosmos-memory-hint\">\n          {{ t`开启后会在总结时提取主要角色和会重复出现的次要角色，并注入到后续提示词中。` }}\n        </div>\n\n        <div class=\"cosmos-memory-row flex-container\">\n          <input class=\"menu_button\" type=\"button\" :value=\"t`查看人物信息`\" @click=\"handle_show_characters\" />\n          <input\n            class=\"menu_button\"\n            type=\"button\"\n            :value=\"is_regenerating_characters ? t`重新生成中...` : t`重新生成`\"\n            :disabled=\"is_regenerate_characters_disabled\"\n            @click=\"handle_regenerate_characters\"\n          />\n        </div>\n\n        <hr class=\"sysHR\" />\n      </div>\n    </div>\n\n    <dialog ref=\"summary_dialog\" class=\"cosmos-memory-dialog\">\n      <div class=\"cosmos-memory-dialog-header\">\n        <b>{{ t`当前聊天总结` }}</b>\n        <button class=\"menu_button\" type=\"button\" @click=\"handle_close_summaries\">{{ t`关闭` }}</button>\n      </div>\n\n      <div v-if=\"stored_summaries.length === 0\" class=\"cosmos-memory-empty\">\n        {{ t`当前聊天记录还没有总结。` }}\n      </div>\n\n      <div v-else class=\"cosmos-memory-summary-list\">\n        <article v-for=\"summary in stored_summaries\" :key=\"summary.message_id\" class=\"cosmos-memory-summary-item\">\n          <div class=\"cosmos-memory-summary-meta\">\n            <b>{{ t`楼层` }} #{{ summary.message_id }}</b>\n            <span>{{ format_time(summary.updated_at) }}</span>\n          </div>\n          <p>{{ summary.summary }}</p>\n        </article>\n      </div>\n    </dialog>\n\n    <dialog ref=\"item_dialog\" class=\"cosmos-memory-dialog\">\n      <div class=\"cosmos-memory-dialog-header\">\n        <b>{{ t`当前聊天物品信息` }}</b>\n        <button class=\"menu_button\" type=\"button\" @click=\"handle_close_items\">{{ t`关闭` }}</button>\n      </div>\n\n      <div v-if=\"stored_items.length === 0\" class=\"cosmos-memory-empty\">\n        {{ t`当前聊天记录还没有物品信息。` }}\n      </div>\n\n      <div v-else class=\"cosmos-memory-summary-list\">\n        <article v-for=\"item in stored_items\" :key=\"item.name\" class=\"cosmos-memory-summary-item\">\n          <div class=\"cosmos-memory-summary-meta\">\n            <b>{{ item.name }}</b>\n          </div>\n          <p>{{ item.brief }}</p>\n        </article>\n      </div>\n    </dialog>\n\n    <dialog ref=\"character_dialog\" class=\"cosmos-memory-dialog\">\n      <div class=\"cosmos-memory-dialog-header\">\n        <b>{{ t`当前聊天人物信息` }}</b>\n        <button class=\"menu_button\" type=\"button\" @click=\"handle_close_characters\">{{ t`关闭` }}</button>\n      </div>\n\n      <div v-if=\"stored_characters.length === 0\" class=\"cosmos-memory-empty\">\n        {{ t`当前聊天记录还没有人物信息。` }}\n      </div>\n\n      <div v-else class=\"cosmos-memory-summary-list\">\n        <section v-if=\"primary_characters.length > 0\">\n          <h4>{{ t`主要角色` }}</h4>\n          <article v-for=\"character in primary_characters\" :key=\"character.name\" class=\"cosmos-memory-summary-item\">\n            <div class=\"cosmos-memory-summary-meta\">\n              <b>{{ character.name }}</b>\n            </div>\n            <dl class=\"cosmos-memory-character-fields\">\n              <template v-if=\"character.background\">\n                <dt>{{ t`背景介绍` }}</dt>\n                <dd>{{ character.background }}</dd>\n              </template>\n              <template v-if=\"character.appearance\">\n                <dt>{{ t`外貌描写` }}</dt>\n                <dd>{{ character.appearance }}</dd>\n              </template>\n              <template v-if=\"character.personality\">\n                <dt>{{ t`性格描写` }}</dt>\n                <dd>{{ character.personality }}</dd>\n              </template>\n            </dl>\n          </article>\n        </section>\n\n        <section v-if=\"secondary_characters.length > 0\">\n          <h4>{{ t`次要角色` }}</h4>\n          <article v-for=\"character in secondary_characters\" :key=\"character.name\" class=\"cosmos-memory-summary-item\">\n            <div class=\"cosmos-memory-summary-meta\">\n              <b>{{ character.name }}</b>\n            </div>\n            <p>{{ character.brief }}</p>\n          </article>\n        </section>\n      </div>\n    </dialog>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { fetchCustomModelNames, sendPing } from '@/api/ai';\nimport { regenerateCharactersFromChat } from '@/core/character-regeneration';\nimport {\n  getStoredCharacters,\n  type PrimaryCharacter,\n  type SecondaryCharacter,\n  type StoredCharacter,\n} from '@/core/characters';\nimport { getStoredItems, type StoredItem } from '@/core/items';\nimport { getStoredMessageSummaries, type MessageSummary } from '@/core/summary';\nimport { getStoredCurrentInfo, type CurrentInfo } from '@/core/current-info';\nimport { useSettingsStore } from '@/store/settings';\nimport { storeToRefs } from 'pinia';\n\ntype TestResult = {\n  type: 'success' | 'error';\n  message: string;\n};\n\nconst { settings } = storeToRefs(useSettingsStore());\n\nconst is_fetching_models = ref(false);\nconst is_testing = ref(false);\nconst is_regenerating_characters = ref(false);\nconst test_result = ref<TestResult | null>(null);\nconst stored_summaries = ref<MessageSummary[]>([]);\nconst stored_characters = ref<StoredCharacter[]>([]);\nconst stored_items = ref<StoredItem[]>([]);\nconst stored_current_info = ref<CurrentInfo>({\n  current_time: '',\n  location: '',\n  characters: {},\n});\nconst summary_dialog = ref<HTMLDialogElement | null>(null);\nconst character_dialog = ref<HTMLDialogElement | null>(null);\nconst item_dialog = ref<HTMLDialogElement | null>(null);\n\nconst model_options = computed(() => {\n  return [...new Set([settings.value.ai.selected_model, ...settings.value.ai.available_models])]\n    .map(model => model.trim())\n    .filter(Boolean);\n});\n\nconst is_test_disabled = computed(() => {\n  if (is_testing.value) {\n    return true;\n  }\n\n  return is_ai_request_disabled.value;\n});\n\nconst is_ai_request_disabled = computed(() => {\n  if (settings.value.ai.use_tavern_api) {\n    return false;\n  }\n\n  return !settings.value.ai.custom_api_url.trim() || !settings.value.ai.selected_model.trim();\n});\n\nconst is_regenerate_characters_disabled = computed(() => {\n  return is_regenerating_characters.value || is_ai_request_disabled.value;\n});\n\nconst primary_characters = computed(() => {\n  return stored_characters.value.filter((character): character is PrimaryCharacter => character.type === 'primary');\n});\n\nconst secondary_characters = computed(() => {\n  return stored_characters.value.filter((character): character is SecondaryCharacter => character.type === 'secondary');\n});\n\nconst current_character_entries = computed(() => {\n  return Object.entries(stored_current_info.value.characters).sort(([left], [right]) => left.localeCompare(right));\n});\n\nasync function handle_fetch_models() {\n  is_fetching_models.value = true;\n  test_result.value = null;\n\n  try {\n    const models = await fetchCustomModelNames(settings.value.ai);\n    settings.value.ai.available_models = models;\n\n    if (!settings.value.ai.selected_model && models.length > 0) {\n      settings.value.ai.selected_model = models[0]!;\n    }\n\n    toastr.success(t`模型列表获取成功。`);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(message);\n    test_result.value = { type: 'error', message };\n  } finally {\n    is_fetching_models.value = false;\n  }\n}\n\nasync function handle_send_test_message() {\n  is_testing.value = true;\n  test_result.value = null;\n\n  try {\n    const response = await sendPing(settings.value.ai);\n    const message = response.trim() || t`AI 返回了空内容。`;\n    test_result.value = { type: 'success', message };\n    toastr.success(t`测试消息发送成功。`);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(message);\n    test_result.value = { type: 'error', message };\n  } finally {\n    is_testing.value = false;\n  }\n}\n\nfunction handle_show_summaries() {\n  stored_summaries.value = getStoredMessageSummaries();\n  refresh_stored_current_info();\n  summary_dialog.value?.showModal();\n}\n\nfunction handle_close_summaries() {\n  summary_dialog.value?.close();\n}\n\nfunction handle_show_characters() {\n  stored_characters.value = getStoredCharacters();\n  character_dialog.value?.showModal();\n}\n\nfunction handle_close_characters() {\n  character_dialog.value?.close();\n}\n\nfunction handle_show_items() {\n  stored_items.value = getStoredItems();\n  item_dialog.value?.showModal();\n}\n\nfunction handle_close_items() {\n  item_dialog.value?.close();\n}\n\nfunction handle_refresh_current_info() {\n  refresh_stored_current_info();\n}\n\nfunction refresh_stored_current_info() {\n  try {\n    stored_current_info.value = getStoredCurrentInfo();\n  } catch (error) {\n    console.warn('[CosmosMemory] 读取当前信息失败', error);\n    stored_current_info.value = {\n      current_time: '',\n      location: '',\n      characters: {},\n    };\n  }\n}\n\nasync function handle_regenerate_characters() {\n  is_regenerating_characters.value = true;\n\n  try {\n    stored_characters.value = await regenerateCharactersFromChat(settings.value.ai);\n    toastr.success(t`人物信息重新生成成功。`);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(message, 'Cosmos Memory');\n  } finally {\n    is_regenerating_characters.value = false;\n  }\n}\n\nfunction format_time(value: string) {\n  if (!value) {\n    return '';\n  }\n\n  const date = new Date(value);\n  if (Number.isNaN(date.getTime())) {\n    return value;\n  }\n\n  return date.toLocaleString();\n}\n\nfunction normalize_retained_original_count() {\n  const count = settings.value.compression.retained_original_assistant_messages;\n  settings.value.compression.retained_original_assistant_messages = Number.isFinite(count)\n    ? Math.max(0, Math.floor(count))\n    : 5;\n}\n</script>\n\n<style scoped>\n.cosmos-memory-row {\n  align-items: center;\n  gap: 8px;\n  margin: 8px 0;\n}\n\n.cosmos-memory-field {\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n  margin: 8px 0;\n}\n\n.cosmos-memory-field > span,\n.cosmos-memory-hint {\n  opacity: 0.85;\n}\n\n.cosmos-memory-section-title {\n  border-bottom: 1px solid var(--SmartThemeBorderColor);\n  margin: 12px 0 8px;\n  padding-bottom: 4px;\n}\n\n.cosmos-memory-current-info {\n  margin: 8px 0;\n}\n\n.cosmos-memory-current-characters {\n  margin-top: 8px;\n}\n\n.cosmos-memory-current-characters-title {\n  font-weight: 700;\n  margin-bottom: 4px;\n}\n\n.cosmos-memory-current-characters dl {\n  margin: 6px 0;\n}\n\n.cosmos-memory-current-characters dt {\n  font-weight: 700;\n}\n\n.cosmos-memory-current-characters dd {\n  margin: 2px 0 0 12px;\n  white-space: pre-wrap;\n}\n\n.cosmos-memory-test-result {\n  border-radius: 8px;\n  margin: 8px 0;\n  padding: 8px 10px;\n  white-space: pre-wrap;\n}\n\n.cosmos-memory-test-result--success {\n  background: rgba(46, 125, 50, 0.22);\n  border: 1px solid #2e7d32;\n}\n\n.cosmos-memory-test-result--error {\n  background: rgba(198, 40, 40, 0.18);\n  border: 1px solid #c62828;\n}\n\n.cosmos-memory-dialog {\n  background: var(--SmartThemeBlurTintColor);\n  border: 1px solid var(--SmartThemeBorderColor);\n  border-radius: 8px;\n  color: var(--SmartThemeBodyColor);\n  max-height: min(720px, 80vh);\n  max-width: min(720px, 90vw);\n  padding: 12px;\n  width: 720px;\n}\n\n.cosmos-memory-dialog::backdrop {\n  background: rgba(0, 0, 0, 0.45);\n}\n\n.cosmos-memory-dialog-header,\n.cosmos-memory-summary-meta {\n  align-items: center;\n  display: flex;\n  gap: 12px;\n  justify-content: space-between;\n}\n\n.cosmos-memory-empty {\n  margin-top: 12px;\n  opacity: 0.85;\n}\n\n.cosmos-memory-summary-list {\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n  margin-top: 12px;\n  overflow-y: auto;\n}\n\n.cosmos-memory-summary-item {\n  border: 1px solid var(--SmartThemeBorderColor);\n  border-radius: 8px;\n  padding: 10px;\n}\n\n.cosmos-memory-summary-item p {\n  margin: 8px 0 0;\n  white-space: pre-wrap;\n}\n\n.cosmos-memory-summary-meta span {\n  font-size: 0.9em;\n  opacity: 0.75;\n}\n\n.cosmos-memory-character-fields {\n  margin: 8px 0 0;\n}\n\n.cosmos-memory-character-fields dt {\n  font-weight: 700;\n  margin-top: 8px;\n}\n\n.cosmos-memory-character-fields dd {\n  margin: 4px 0 0;\n  white-space: pre-wrap;\n}\n</style>\n","import { registerSummaryEvents } from '@/core/events';\nimport Panel from '@/Panel.vue';\nimport { App } from 'vue';\n\nconst app = createApp(Panel);\n\nconst pinia = createPinia();\napp.use(pinia);\n\ndeclare module 'vue' {\n  interface ComponentCustomProperties {\n    t: typeof t;\n  }\n}\nconst i18n = {\n  install: (app: App) => {\n    app.config.globalProperties.t = t;\n  },\n};\napp.use(i18n);\n\nexport function initPanel() {\n  console.info('[CosmosMemory] 初始化插件面板');\n  const $app = $('<div id=\"cosmos_memory\">').appendTo('#extensions_settings2');\n  app.mount($app[0]);\n  registerSummaryEvents();\n}\n","import '@/global.css';\nimport { initPanel } from '@/panel';\n\n$(() => {\n  initPanel();\n});\n"],"names":["_a","$constructor","name","initializer","params","init","inst","def","_zod","Object","defineProperty","value","constr","_","traits","Set","enumerable","has","add","proto","prototype","keys","i","length","k","bind","Parent","Definition","this","deferred","fn","Symbol","hasInstance","$ZodAsyncError","Error","constructor","super","$ZodEncodeError","globalThis","__zod_globalConfig","globalConfig","config","newConfig","getEnumValues","entries","numericValues","values","filter","v","indexOf","map","jsonStringifyReplacer","toString","cached","getter","nullish","input","cleanRegex","source","start","startsWith","end","endsWith","slice","EVALUATING","defineLazy","object","key","get","undefined","set","configurable","assignProp","target","prop","writable","mergeDefs","defs","mergedDescriptors","descriptors","getOwnPropertyDescriptors","assign","defineProperties","esc","str","JSON","stringify","captureStackTrace","_args","isObject","data","Array","isArray","allowsEval","jitless","navigator","userAgent","includes","Function","isPlainObject","o","ctor","prot","hasOwnProperty","call","shallowClone","Map","propertyKeyTypes","escapeRegex","replace","clone","cl","parent","normalizeParams","_params","error","message","NUMBER_FORMAT_RANGES","safeint","Number","MIN_SAFE_INTEGER","MAX_SAFE_INTEGER","int32","uint32","float32","float64","MAX_VALUE","aborted","x","startIndex","issues","continue","explicitlyAborted","prefixIssues","path","iss","unshift","unwrapMessage","finalizeIssue","ctx","customError","localeError","_inst","_continue","_input","rest","reportInput","getLengthableOrigin","issue","args","code","util.jsonStringifyReplacer","$ZodError","$ZodRealError","toDotPath","_path","segs","seg","push","String","test","join","_parse","_Err","schema","_ctx","async","result","run","Promise","core.$ZodAsyncError","e","Err","util.finalizeIssue","core.config","util.captureS