';\nconst CHARACTER_STORAGE_PATH = `${STORAGE_ROOT}.characters`;\nconst CHARACTER_PROMPT_ID = 'cosmos_memory_characters';\nconst CHARACTER_PROMPT_DEPTH = 9999;\n\nexport type CharacterKind = 'primary' | 'secondary';\nexport type CharacterOperationType = 'add' | 'set' | 'delete';\n\nexport type CharacterOperation = {\n  type: CharacterOperationType;\n  character_type: CharacterKind;\n  name: string;\n  background?: string;\n  appearance?: string;\n  personality?: string;\n  brief?: string;\n};\n\nexport type PrimaryCharacter = {\n  type: 'primary';\n  name: string;\n  background: string;\n  appearance: string;\n  personality: string;\n};\n\nexport type SecondaryCharacter = {\n  type: 'secondary';\n  name: string;\n  brief: string;\n};\n\nexport type StoredCharacter = PrimaryCharacter | SecondaryCharacter;\n\ntype SummaryWithCharacterOperations = {\n  character_operations?: CharacterOperation[];\n};\n\nexport const CharacterOperationResponse = z.object({\n  type: z.enum(['add', 'set', 'delete']),\n  character_type: z.enum(['primary', 'secondary']),\n  name: z.string().trim().min(1),\n  background: z.string().trim().optional().default(''),\n  appearance: z.string().trim().optional().default(''),\n  personality: z.string().trim().optional().default(''),\n  brief: z.string().trim().optional().default(''),\n});\n\nexport const CharacterOperationsResponse = z.array(CharacterOperationResponse).default([]);\n\nexport const StoredCharacterResponse = z.discriminatedUnion('type', [\n  z.object({\n    type: z.literal('primary'),\n    name: z.string().trim().min(1),\n    background: z.string().trim().default(''),\n    appearance: z.string().trim().default(''),\n    personality: z.string().trim().default(''),\n  }),\n  z.object({\n    type: z.literal('secondary'),\n    name: z.string().trim().min(1),\n    brief: z.string().trim().default(''),\n  }),\n]);\n\nexport const StoredCharactersResponse = z.array(StoredCharacterResponse).default([]);\n\nlet character_prompt_injected = false;\n\nfunction normalizeText(value: unknown): string {\n  return typeof value === 'string' ? value.trim() : '';\n}\n\nexport function normalizeCharacterKey(name: string): string {\n  return name.trim().replace(/\\s+/g, ' ').toLowerCase();\n}\n\nfunction isStoredCharacter(value: unknown): value is StoredCharacter {\n  if (typeof value !== 'object' || value === null) {\n    return false;\n  }\n\n  const character = value as Partial<StoredCharacter>;\n  if (character.type === 'primary') {\n    return (\n      typeof character.name === 'string' &&\n      typeof character.background === 'string' &&\n      typeof character.appearance === 'string' &&\n      typeof character.personality === 'string'\n    );\n  }\n\n  return character.type === 'secondary' && typeof character.name === 'string' && typeof character.brief === 'string';\n}\n\nfunction getStoredCharacterRecord(): Record<string, StoredCharacter> {\n  const variables = window.TavernHelper.getVariables({ type: 'chat' });\n  const characters = _.get(variables, CHARACTER_STORAGE_PATH, {}) as Record<string, unknown>;\n  return Object.fromEntries(\n    Object.entries(characters).filter((entry): entry is [string, StoredCharacter] => {\n      const [key, character] = entry;\n      return Boolean(key) && isStoredCharacter(character);\n    }),\n  );\n}\n\nexport function getStoredCharacters(): StoredCharacter[] {\n  return Object.values(getStoredCharacterRecord()).sort((left, right) => {\n    if (left.type !== right.type) {\n      return left.type === 'primary' ? -1 : 1;\n    }\n\n    return left.name.localeCompare(right.name);\n  });\n}\n\nfunction mergeCharacterOperation(\n  characters: Record<string, StoredCharacter>,\n  operation: CharacterOperation,\n): Record<string, StoredCharacter> {\n  const name = normalizeText(operation.name);\n  const key = normalizeCharacterKey(name);\n  if (!key) {\n    return characters;\n  }\n\n  if (operation.type === 'delete') {\n    _.unset(characters, key);\n    return characters;\n  }\n\n  const existing = characters[key];\n  if (operation.character_type === 'primary') {\n    const next: PrimaryCharacter = {\n      type: 'primary',\n      name: name || existing?.name || '',\n      background: existing?.type === 'primary' ? existing.background : '',\n      appearance: existing?.type === 'primary' ? existing.appearance : '',\n      personality: existing?.type === 'primary' ? existing.personality : '',\n    };\n    const background = normalizeText(operation.background);\n    const appearance = normalizeText(operation.appearance);\n    const personality = normalizeText(operation.personality);\n\n    if (background) {\n      next.background = background;\n    }\n    if (appearance) {\n      next.appearance = appearance;\n    }\n    if (personality) {\n      next.personality = personality;\n    }\n\n    characters[key] = next;\n    return characters;\n  }\n\n  const next: SecondaryCharacter = {\n    type: 'secondary',\n    name: name || existing?.name || '',\n    brief: existing?.type === 'secondary' ? existing.brief : '',\n  };\n  const brief = normalizeText(operation.brief);\n  if (brief) {\n    next.brief = brief;\n  }\n\n  characters[key] = next;\n  return characters;\n}\n\nexport function applyCharacterOperations(operations: CharacterOperation[]): StoredCharacter[] {\n  const characters = getStoredCharacterRecord();\n  for (const operation of operations) {\n    mergeCharacterOperation(characters, operation);\n  }\n\n  saveCharacterRecord(characters);\n  return getStoredCharacters();\n}\n\nexport function rebuildStoredCharactersFromSummaries(summaries: SummaryWithCharacterOperations[]): StoredCharacter[] {\n  const characters: Record<string, StoredCharacter> = {};\n  for (const summary of summaries) {\n    for (const operation of summary.character_operations ?? []) {\n      mergeCharacterOperation(characters, operation);\n    }\n  }\n\n  saveCharacterRecord(characters);\n  return Object.values(characters).sort((left, right) => left.name.localeCompare(right.name));\n}\n\nfunction saveCharacterRecord(characters: Record<string, StoredCharacter>) {\n  window.TavernHelper.updateVariablesWith(\n    variables => {\n      _.set(variables, CHARACTER_STORAGE_PATH, characters);\n      return variables;\n    },\n    { type: 'chat' },\n  );\n}\n\nexport function replaceStoredCharacters(characters: StoredCharacter[]): StoredCharacter[] {\n  const next: Record<string, StoredCharacter> = {};\n  for (const character of characters) {\n    const key = normalizeCharacterKey(character.name);\n    if (key) {\n      next[key] = character;\n    }\n  }\n\n  saveCharacterRecord(next);\n  return getStoredCharacters();\n}\n\nexport function formatCharactersForPrompt(characters: StoredCharacter[] = getStoredCharacters()): string {\n  const primary_characters = characters.filter(\n    (character): character is PrimaryCharacter => character.type === 'primary',\n  );\n  const secondary_characters = characters.filter(\n    (character): character is SecondaryCharacter => character.type === 'secondary',\n  );\n\n  if (primary_characters.length === 0 && secondary_characters.length === 0) {\n    return '';\n  }\n\n  const lines = ['[CosmosMemory 人物信息]', '以下是已经记录的人物信息，优先沿用这些设定，不要重复发明同名人物。'];\n\n  if (primary_characters.length > 0) {\n    lines.push('', '主要角色：');\n    for (const character of primary_characters) {\n      lines.push(`- 姓名：${character.name}`);\n      if (character.background) {\n        lines.push(`  背景介绍：${character.background}`);\n      }\n      if (character.appearance) {\n        lines.push(`  外貌描写：${character.appearance}`);\n      }\n      if (character.personality) {\n        lines.push(`  性格描写：${character.personality}`);\n      }\n    }\n  }\n\n  if (secondary_characters.length > 0) {\n    lines.push('', '次要角色：');\n    for (const character of secondary_characters) {\n      lines.push(`- 姓名/身份：${character.name}`);\n      if (character.brief) {\n        lines.push(`  简介：${character.brief}`);\n      }\n    }\n  }\n\n  lines.push('[/CosmosMemory 人物信息]');\n  return lines.join('\\n');\n}\n\nfunction clearChatCharacterPrompt() {\n  if (!character_prompt_injected) {\n    return;\n  }\n\n  window.TavernHelper.uninjectPrompts([CHARACTER_PROMPT_ID]);\n  character_prompt_injected = false;\n}\n\nexport function clearCharacterPromptInjection() {\n  try {\n    window.TavernHelper.uninjectPrompts([CHARACTER_PROMPT_ID]);\n  } catch (error) {\n    console.warn('[CosmosMemory] 清理人物信息聊天注入失败', error);\n  }\n  character_prompt_injected = false;\n}\n\nexport function applyCharacterPromptInjection(enabled: boolean): boolean {\n  clearChatCharacterPrompt();\n\n  if (!enabled) {\n    return false;\n  }\n\n  const content = formatCharactersForPrompt();\n  if (!content) {\n    return false;\n  }\n\n  window.TavernHelper.injectPrompts(\n    [\n      {\n        id: CHARACTER_PROMPT_ID,\n        position: 'in_chat',\n        depth: CHARACTER_PROMPT_DEPTH,\n        role: 'system',\n        content,\n      },\n    ],\n    { once: true },\n  );\n  character_prompt_injected = true;\n  return true;\n}\n","const STORAGE_ROOT = 'cosmos_memory';\nconst ITEM_STORAGE_PATH = `${STORAGE_ROOT}.items`;\nconst ITEM_PROMPT_ID = 'cosmos_memory_items';\nconst ITEM_PROMPT_DEPTH = 10000;\n\nexport type ItemOperationType = 'add' | 'set' | 'delete';\n\nexport type ItemOperation = {\n  type: ItemOperationType;\n  name: string;\n  brief?: string;\n};\n\nexport type StoredItem = {\n  name: string;\n  brief: string;\n};\n\ntype SummaryWithItemOperations = {\n  item_operations?: ItemOperation[];\n};\n\nexport const ItemOperationResponse = z.object({\n  type: z.enum(['add', 'set', 'delete']),\n  name: z.string().trim().min(1),\n  brief: z.string().trim().optional().default(''),\n});\n\nexport const ItemOperationsResponse = z.array(ItemOperationResponse).default([]);\n\nlet item_prompt_injected = false;\n\nfunction normalizeText(value: unknown): string {\n  return typeof value === 'string' ? value.trim() : '';\n}\n\nexport function normalizeItemKey(name: string): string {\n  return name.trim().replace(/\\s+/g, ' ').toLowerCase();\n}\n\nfunction isStoredItem(value: unknown): value is StoredItem {\n  return (\n    typeof value === 'object' &&\n    value !== null &&\n    typeof (value as Partial<StoredItem>).name === 'string' &&\n    typeof (value as Partial<StoredItem>).brief === 'string'\n  );\n}\n\nfunction getStoredItemRecord(): Record<string, StoredItem> {\n  const variables = window.TavernHelper.getVariables({ type: 'chat' });\n  const items = _.get(variables, ITEM_STORAGE_PATH, {}) as Record<string, unknown>;\n  return Object.fromEntries(\n    Object.entries(items).filter((entry): entry is [string, StoredItem] => {\n      const [key, item] = entry;\n      return Boolean(key) && isStoredItem(item);\n    }),\n  );\n}\n\nexport function getStoredItems(): StoredItem[] {\n  return Object.values(getStoredItemRecord()).sort((left, right) => left.name.localeCompare(right.name));\n}\n\nfunction mergeItemOperation(items: Record<string, StoredItem>, operation: ItemOperation): Record<string, StoredItem> {\n  const name = normalizeText(operation.name);\n  const key = normalizeItemKey(name);\n  if (!key) {\n    return items;\n  }\n\n  if (operation.type === 'delete') {\n    _.unset(items, key);\n    return items;\n  }\n\n  const existing = items[key];\n  const brief = normalizeText(operation.brief);\n  items[key] = {\n    name: name || existing?.name || '',\n    brief: brief || existing?.brief || '',\n  };\n  return items;\n}\n\nexport function applyItemOperations(operations: ItemOperation[]): StoredItem[] {\n  const items = getStoredItemRecord();\n  for (const operation of operations) {\n    mergeItemOperation(items, operation);\n  }\n\n  saveItemRecord(items);\n  return getStoredItems();\n}\n\nexport function rebuildStoredItemsFromSummaries(summaries: SummaryWithItemOperations[]): StoredItem[] {\n  const items: Record<string, StoredItem> = {};\n  for (const summary of summaries) {\n    for (const operation of summary.item_operations ?? []) {\n      mergeItemOperation(items, operation);\n    }\n  }\n\n  saveItemRecord(items);\n  return Object.values(items).sort((left, right) => left.name.localeCompare(right.name));\n}\n\nfunction saveItemRecord(items: Record<string, StoredItem>) {\n  window.TavernHelper.updateVariablesWith(\n    variables => {\n      _.set(variables, ITEM_STORAGE_PATH, items);\n      return variables;\n    },\n    { type: 'chat' },\n  );\n}\n\nexport function formatItemsForPrompt(items: StoredItem[] = getStoredItems()): string {\n  if (items.length === 0) {\n    return '';\n  }\n\n  const lines = ['[CosmosMemory 物品信息]', '以下是已经记录的重要道具、装备、礼物、信物等物品状态。'];\n  for (const item of items) {\n    lines.push(`- 物品名：${item.name}`);\n    if (item.brief) {\n      lines.push(`  简介：${item.brief}`);\n    }\n  }\n  lines.push('[/CosmosMemory 物品信息]');\n  return lines.join('\\n');\n}\n\nfunction clearChatItemPrompt() {\n  if (!item_prompt_injected) {\n    return;\n  }\n\n  window.TavernHelper.uninjectPrompts([ITEM_PROMPT_ID]);\n  item_prompt_injected = false;\n}\n\nexport function applyItemPromptInjection(enabled: boolean): boolean {\n  clearChatItemPrompt();\n\n  if (!enabled) {\n    return false;\n  }\n\n  const content = formatItemsForPrompt();\n  if (!content) {\n    return false;\n  }\n\n  window.TavernHelper.injectPrompts(\n    [\n      {\n        id: ITEM_PROMPT_ID,\n        position: 'in_chat',\n        depth: ITEM_PROMPT_DEPTH,\n        role: 'system',\n        content,\n      },\n    ],\n    { once: true },\n  );\n  item_prompt_injected = true;\n  return true;\n}\n","const STORAGE_ROOT = 'cosmos_memory';\nconst TIME_STORAGE_PATH = `${STORAGE_ROOT}.time`;\nconst TIME_PROMPT_ID = 'cosmos_memory_time';\nconst TIME_PROMPT_DEPTH = 10001;\n\nexport type StoryTimeUpdate = {\n  current_time: string;\n  elapsed_time?: string;\n  reason?: string;\n};\n\ntype SummaryWithTimeUpdate = {\n  time_update?: StoryTimeUpdate | null;\n};\n\nexport const TimeUpdateResponse = z.object({\n  current_time: z.string().trim().default(''),\n  elapsed_time: z.string().trim().optional().default(''),\n  reason: z.string().trim().optional().default(''),\n});\n\nlet time_prompt_injected = false;\n\nfunction normalizeTime(value: unknown): string {\n  return typeof value === 'string' ? value.trim() : '';\n}\n\nexport function getStoredTime(): string {\n  const variables = window.TavernHelper.getVariables({ type: 'chat' });\n  return normalizeTime(_.get(variables, TIME_STORAGE_PATH, ''));\n}\n\nfunction saveStoredTime(current_time: string) {\n  window.TavernHelper.updateVariablesWith(\n    variables => {\n      const normalized_time = current_time.trim();\n      if (normalized_time) {\n        _.set(variables, TIME_STORAGE_PATH, normalized_time);\n      } else {\n        _.unset(variables, TIME_STORAGE_PATH);\n      }\n      return variables;\n    },\n    { type: 'chat' },\n  );\n}\n\nexport function applyTimeUpdate(update: StoryTimeUpdate | null | undefined): string {\n  const current_time = normalizeTime(update?.current_time);\n  if (!current_time) {\n    return getStoredTime();\n  }\n\n  saveStoredTime(current_time);\n  return current_time;\n}\n\nexport function rebuildStoredTimeFromSummaries(summaries: SummaryWithTimeUpdate[]): string {\n  const current_time = summaries.reduce((time, summary) => {\n    return normalizeTime(summary.time_update?.current_time) || time;\n  }, '');\n\n  saveStoredTime(current_time);\n  return current_time;\n}\n\nexport function formatTimeForPrompt(current_time: string = getStoredTime()): string {\n  const normalized_time = current_time.trim();\n  if (!normalized_time) {\n    return '';\n  }\n\n  return ['[CosmosMemory 时间]', `当前故事时间：${normalized_time}`, '[/CosmosMemory 时间]'].join('\\n');\n}\n\nexport function formatTimeForSummaryRequest(current_time: string): string {\n  const normalized_time = current_time.trim();\n  if (normalized_time) {\n    return formatTimeForPrompt(normalized_time);\n  }\n\n  return [\n    '[CosmosMemory 时间]',\n    '当前故事时间：未记录，请根据本楼层剧情生成符合背景的当前时间。',\n    '[/CosmosMemory 时间]',\n  ].join('\\n');\n}\n\nfunction clearChatTimePrompt() {\n  if (!time_prompt_injected) {\n    return;\n  }\n\n  window.TavernHelper.uninjectPrompts([TIME_PROMPT_ID]);\n  time_prompt_injected = false;\n}\n\nexport function clearTimePromptInjection() {\n  try {\n    window.TavernHelper.uninjectPrompts([TIME_PROMPT_ID]);\n  } catch (error) {\n    console.warn('[CosmosMemory] 清理时间信息聊天注入失败', error);\n  }\n  time_prompt_injected = false;\n}\n\nexport function applyTimePromptInjection(enabled: boolean): boolean {\n  clearChatTimePrompt();\n\n  if (!enabled) {\n    return false;\n  }\n\n  const content = formatTimeForPrompt();\n  if (!content) {\n    return false;\n  }\n\n  window.TavernHelper.injectPrompts(\n    [\n      {\n        id: TIME_PROMPT_ID,\n        position: 'in_chat',\n        depth: TIME_PROMPT_DEPTH,\n        role: 'system',\n        content,\n      },\n    ],\n    { once: true },\n  );\n  time_prompt_injected = true;\n  return true;\n}\n","export function validateInplace<T>(schema: z.ZodType<T>, data: unknown): T {\n  const result = parsePrettified(schema, data ?? {});\n  if (typeof data !== 'object' || data === null) {\n    return result;\n  }\n\n  return _.assign(data, result) as T;\n}\n\nexport function parsePrettified<T>(schema: z.ZodType<T>, data: unknown): T {\n  const result = schema.safeParse(data);\n  if (!result.success) {\n    throw Error(z.prettifyError(result.error));\n  }\n  return result.data;\n}\n","import type { AiSettings } from '@/type/settings';\nimport {\n  CharacterOperationsResponse,\n  StoredCharactersResponse,\n  formatCharactersForPrompt,\n  type CharacterOperation,\n  type StoredCharacter,\n} from '@/core/characters';\nimport { ItemOperationsResponse, formatItemsForPrompt, type ItemOperation, type StoredItem } from '@/core/items';\nimport { TimeUpdateResponse, formatTimeForSummaryRequest, type StoryTimeUpdate } from '@/core/time';\nimport { parsePrettified } from '@/util/zod';\n\nconst TEST_MESSAGE = '!ping';\nconst DEFAULT_CUSTOM_API_SOURCE = 'openai';\nconst DEEPSEEK_API_SOURCE = 'deepseek';\nconst SUMMARY_MAX_TOKENS = 2048;\n\ntype CustomApi = NonNullable<GenerateConfig['custom_api']>;\n\nconst SummaryResponse = z.object({\n  summary: z.string().trim().min(1),\n});\n\nconst SummaryWithMemoryResponse = z.object({\n  summary: z.string().trim().min(1),\n  characters: CharacterOperationsResponse.optional().default([]),\n  item_operations: ItemOperationsResponse.optional().default([]),\n  time_update: TimeUpdateResponse.nullable().optional(),\n});\n\nconst CharacterExtractionResponse = z.object({\n  characters: StoredCharactersResponse,\n});\n\nexport type SummaryGenerationResult = {\n  summary: string;\n  characters: CharacterOperation[];\n  item_operations: ItemOperation[];\n  time_update?: StoryTimeUpdate | null;\n};\n\nexport type SummaryGenerationOptions = {\n  characters_enabled?: boolean;\n  stored_characters?: StoredCharacter[];\n  items_enabled?: boolean;\n  stored_items?: StoredItem[];\n  time_enabled?: boolean;\n  current_time?: string;\n};\n\nconst SUMMARY_SYSTEM_PROMPT =\n  '你是剧情摘要器。请把用户提供的内容压缩成一段连贯的故事摘要，只保留已发生的剧情事实、角色行动、状态与关系变化。输出必须是流畅的叙述段落，不要使用分类标签或清单格式，不要续写剧情，不要加入原文没有的信息。';\n\nconst SUMMARY_JSON_INSTRUCTION =\n  '请总结以下剧情内容，只返回 JSON。格式：{\"summary\":\"连贯的剧情摘要\"}。不要使用 Markdown 代码块，不要返回额外解释。';\n\nconst CHARACTER_EXTRACTION_INSTRUCTION =\n  '同时提取本楼层明确新增、更新或删除的人物信息，返回 characters 数组。主要角色是剧情中有明确戏份的角色，需要保存姓名、背景介绍、外貌描写、性格描写；次要角色是会多次出现但不重要的 NPC，例如酒馆老板、公会看板娘，只需要保存姓名或身份和简介。一次性路人、杂兵、临时敌人不要记录。只返回本楼层带来的变化，不要重复返回没有变化的已有人物。';\n\nconst ITEM_EXTRACTION_INSTRUCTION =\n  '同时提取本楼层明确新增、更新或删除的重要物品信息，返回 item_operations 数组。只记录会影响剧情的重要道具，例如武器、装备、礼物、信物、钥匙、契约、任务物品等；不要记录普通食物、零钱、临时杂物、随手可得且不影响剧情的物品。物品被使用、损坏、交出、消耗或状态改变时要及时用 set 更新简介；物品彻底失去剧情意义或不再持有时可用 delete 删除。只返回本楼层带来的变化，不要重复返回没有变化的已有物品。';\n\nconst TIME_EXTRACTION_INSTRUCTION =\n  '同时维护当前故事时间，返回 time_update。若已有当前时间为空，请根据本楼层剧情内容生成一个符合故事背景的当前时间；若已有当前时间不为空，请根据本楼层剧情明确或可合理推断的耗时更新当前时间。若本楼层没有时间流逝或无法判断耗时，则保持当前时间不变。不要使用现实时间，除非剧情本身就是现实背景。';\n\nconst TIME_JSON_FIELD_INSTRUCTION =\n  '\"time_update\":{\"current_time\":\"本楼层结束后的当前故事时间\",\"elapsed_time\":\"本楼层消耗的剧情时间，没有则为空字符串\",\"reason\":\"更新时间的依据，没有则为空字符串\"}';\n\nconst FULL_CHARACTER_EXTRACTION_SYSTEM_PROMPT =\n  '你是剧情人物档案整理器。请阅读用户提供的所有 AI 回复原文，整理剧情中需要长期记忆的人物信息。只记录有明确戏份的主要角色，以及会多次出现但不重要的次要 NPC，例如酒馆老板、公会看板娘。一次性路人、杂兵、临时敌人不要记录。不要续写剧情，不要加入原文没有的信息。';\n\nconst FULL_CHARACTER_JSON_INSTRUCTION =\n  '请从以下剧情记录中整理所有需要保存的人物，只返回 JSON。格式：{\"characters\":[{\"type\":\"primary|secondary\",\"name\":\"姓名或身份\",\"background\":\"主要角色背景介绍，没有则为空字符串\",\"appearance\":\"主要角色外貌描写，没有则为空字符串\",\"personality\":\"主要角色性格描写，没有则为空字符串\",\"brief\":\"次要角色简介，没有则为空字符串\"}]}。不要使用 Markdown 代码块，不要返回额外解释。';\n\nfunction inferCustomApiSource(settings: AiSettings): string {\n  const target = `${settings.custom_api_url} ${settings.selected_model}`.toLowerCase();\n  if (target.includes('deepseek')) {\n    return DEEPSEEK_API_SOURCE;\n  }\n\n  return DEFAULT_CUSTOM_API_SOURCE;\n}\n\nfunction buildCustomApi(settings: AiSettings): CustomApi | undefined {\n  if (settings.use_tavern_api) {\n    return undefined;\n  }\n\n  const apiurl = settings.custom_api_url.trim();\n  if (!apiurl) {\n    throw new Error('请先填写自定义端点。');\n  }\n\n  const key = settings.custom_api_key.trim();\n  const model = settings.selected_model.trim();\n  if (!model) {\n    throw new Error('请选择模型。');\n  }\n\n  return {\n    apiurl,\n    key: key || undefined,\n    model: model || undefined,\n    source: inferCustomApiSource(settings),\n    max_tokens: SUMMARY_MAX_TOKENS,\n  };\n}\n\nexport async function fetchCustomModelNames(settings: AiSettings): Promise<string[]> {\n  const apiurl = settings.custom_api_url.trim();\n  if (!apiurl) {\n    throw new Error('请先填写自定义端点。');\n  }\n\n  const models = await window.TavernHelper.getModelList({\n    apiurl,\n    key: settings.custom_api_key.trim() || undefined,\n  });\n\n  return [...new Set(models)].filter(Boolean).sort((left, right) => left.localeCompare(right));\n}\n\nexport async function sendPing(settings: AiSettings): Promise<string> {\n  const result = await window.TavernHelper.generateRaw({\n    should_silence: true,\n    custom_api: buildCustomApi(settings),\n    ordered_prompts: [{ role: 'user', content: TEST_MESSAGE }],\n  });\n\n  if (typeof result !== 'string') {\n    return result.content;\n  }\n\n  return result;\n}\n\nfunction parseSummaryJson(raw: string, options: SummaryGenerationOptions = {}): SummaryGenerationResult {\n  const text = raw.trim();\n  const fenced = text.match(/```(?:json)?\\s*([\\s\\S]*?)\\s*```/i)?.[1]?.trim();\n  const json_text = fenced ?? text.match(/\\{[\\s\\S]*\\}/)?.[0] ?? text;\n  const parsed = JSON.parse(json_text);\n\n  if (!hasMemoryExtraction(options)) {\n    return {\n      summary: parsePrettified(SummaryResponse, parsed).summary,\n      characters: [],\n      item_operations: [],\n    };\n  }\n\n  const result = parsePrettified(SummaryWithMemoryResponse, parsed);\n  return {\n    summary: result.summary,\n    characters: options.characters_enabled ? result.characters : [],\n    item_operations: options.items_enabled ? result.item_operations : [],\n    time_update: options.time_enabled ? (result.time_update ?? null) : null,\n  };\n}\n\nfunction hasMemoryExtraction(options: SummaryGenerationOptions): boolean {\n  return options.characters_enabled === true || options.items_enabled === true || options.time_enabled === true;\n}\n\nfunction buildSummaryContent(content: string, options: SummaryGenerationOptions): string {\n  if (!hasMemoryExtraction(options)) {\n    return content;\n  }\n\n  const memory_sections = [\n    options.time_enabled ? formatTimeForSummaryRequest(options.current_time ?? '') : '',\n    options.items_enabled ? formatItemsForPrompt(options.stored_items ?? []) : '',\n    options.characters_enabled ? formatCharactersForPrompt(options.stored_characters ?? []) : '',\n  ].filter(Boolean);\n\n  if (memory_sections.length === 0) {\n    return content;\n  }\n\n  return `${memory_sections.join('\\n\\n')}\\n\\n[本楼层回复]\\n${content}`;\n}\n\nfunction buildSummarySystemPrompt(options: SummaryGenerationOptions): string {\n  const instructions = [SUMMARY_SYSTEM_PROMPT];\n\n  if (options.time_enabled) {\n    instructions.push(TIME_EXTRACTION_INSTRUCTION);\n  }\n\n  if (options.items_enabled) {\n    instructions.push(ITEM_EXTRACTION_INSTRUCTION);\n  }\n\n  if (options.characters_enabled) {\n    instructions.push(CHARACTER_EXTRACTION_INSTRUCTION);\n  }\n\n  return instructions.join('\\n');\n}\n\nfunction buildSummaryJsonInstruction(options: SummaryGenerationOptions): string {\n  if (!hasMemoryExtraction(options)) {\n    return SUMMARY_JSON_INSTRUCTION;\n  }\n\n  const fields = ['\"summary\":\"连贯的剧情摘要\"'];\n  if (options.time_enabled) {\n    fields.push(TIME_JSON_FIELD_INSTRUCTION);\n  }\n  if (options.items_enabled) {\n    fields.push(\n      '\"item_operations\":[{\"type\":\"add|set|delete\",\"name\":\"物品名\",\"brief\":\"物品简介或当前状态，没有则为空字符串\"}]',\n    );\n  }\n  if (options.characters_enabled) {\n    fields.push(\n      '\"characters\":[{\"type\":\"add|set|delete\",\"character_type\":\"primary|secondary\",\"name\":\"姓名或身份\",\"background\":\"主要角色背景介绍，没有则为空字符串\",\"appearance\":\"主要角色外貌描写，没有则为空字符串\",\"personality\":\"主要角色性格描写，没有则为空字符串\",\"brief\":\"次要角色简介，没有则为空字符串\"}]',\n    );\n  }\n\n  return `请总结以下剧情内容，只返回 JSON。格式：{${fields.join(',')}}。不要使用 Markdown 代码块，不要返回额外解释。`;\n}\n\nfunction buildStructuredSummarySchema(options: SummaryGenerationOptions): JsonSchema {\n  const properties: Record<string, unknown> = {\n    summary: {\n      type: 'string',\n      description: '压缩后的剧情摘要',\n    },\n  };\n  const required = ['summary'];\n\n  if (options.time_enabled) {\n    properties.time_update = {\n      type: 'object',\n      description: '本楼层结束后的当前故事时间；没有变化时 current_time 保持原值',\n      properties: {\n        current_time: {\n          type: 'string',\n          description: '本楼层结束后的当前故事时间',\n        },\n        elapsed_time: {\n          type: 'string',\n          description: '本楼层消耗的剧情时间；没有则为空字符串',\n        },\n        reason: {\n          type: 'string',\n          description: '更新时间的依据；没有则为空字符串',\n        },\n      },\n      required: ['current_time', 'elapsed_time', 'reason'],\n      additionalProperties: false,\n    };\n    required.push('time_update');\n  }\n\n  if (options.items_enabled) {\n    properties.item_operations = {\n      type: 'array',\n      description: '本楼层带来的重要物品信息变更；没有变化时返回空数组',\n      items: {\n        type: 'object',\n        properties: {\n          type: {\n            type: 'string',\n            enum: ['add', 'set', 'delete'],\n            description: '物品操作类型',\n          },\n          name: {\n            type: 'string',\n            description: '物品名',\n          },\n          brief: {\n            type: 'string',\n            description: '物品简介或当前状态；不适用或无变化时返回空字符串',\n          },\n        },\n        required: ['type', 'name', 'brief'],\n        additionalProperties: false,\n      },\n    };\n    required.push('item_operations');\n  }\n\n  if (options.characters_enabled) {\n    properties.characters = {\n      type: 'array',\n      description: '本楼层带来的人物信息变更；没有变化时返回空数组',\n      items: {\n        type: 'object',\n        properties: {\n          type: {\n            type: 'string',\n            enum: ['add', 'set', 'delete'],\n            description: '人物操作类型',\n          },\n          character_type: {\n            type: 'string',\n            enum: ['primary', 'secondary'],\n            description: '人物重要程度',\n          },\n          name: {\n            type: 'string',\n            description: '角色全名，或次要角色的稳定身份称呼',\n          },\n          background: {\n            type: 'string',\n            description: '主要角色背景介绍；不适用或无变化时返回空字符串',\n          },\n          appearance: {\n            type: 'string',\n            description: '主要角色外貌描写；不适用或无变化时返回空字符串',\n          },\n          personality: {\n            type: 'string',\n            description: '主要角色性格描写；不适用或无变化时返回空字符串',\n          },\n          brief: {\n            type: 'string',\n            description: '次要角色简介；不适用或无变化时返回空字符串',\n          },\n        },\n        required: ['type', 'character_type', 'name', 'background', 'appearance', 'personality', 'brief'],\n        additionalProperties: false,\n      },\n    };\n    required.push('characters');\n  }\n\n  return {\n    name: hasMemoryExtraction(options) ? 'cosmos_memory_message_summary_with_memory' : 'cosmos_memory_message_summary',\n    description: hasMemoryExtraction(options) ? '单条剧情回复摘要和记忆变更' : '单条剧情回复摘要',\n    strict: true,\n    value: {\n      type: 'object',\n      properties,\n      required,\n      additionalProperties: false,\n    },\n  };\n}\n\nfunction buildFullCharacterExtractionSchema(): JsonSchema {\n  return {\n    name: 'cosmos_memory_full_characters',\n    description: '当前聊天中的完整人物信息表',\n    strict: true,\n    value: {\n      type: 'object',\n      properties: {\n        characters: {\n          type: 'array',\n          description: '需要长期保存的人物信息',\n          items: {\n            type: 'object',\n            properties: {\n              type: {\n                type: 'string',\n                enum: ['primary', 'secondary'],\n                description: '人物重要程度',\n              },\n              name: {\n                type: 'string',\n                description: '主要角色全名，或次要角色的稳定身份称呼',\n              },\n              background: {\n                type: 'string',\n                description: '主要角色背景介绍；不适用或无资料时返回空字符串',\n              },\n              appearance: {\n                type: 'string',\n                description: '主要角色外貌描写；不适用或无资料时返回空字符串',\n              },\n              personality: {\n                type: 'string',\n                description: '主要角色性格描写；不适用或无资料时返回空字符串',\n              },\n              brief: {\n                type: 'string',\n                description: '次要角色简介；不适用或无资料时返回空字符串',\n              },\n            },\n            required: ['type', 'name', 'background', 'appearance', 'personality', 'brief'],\n            additionalProperties: false,\n          },\n        },\n      },\n      required: ['characters'],\n      additionalProperties: false,\n    },\n  };\n}\n\nfunction parseFullCharacterExtractionJson(raw: string): StoredCharacter[] {\n  const text = raw.trim();\n  const fenced = text.match(/```(?:json)?\\s*([\\s\\S]*?)\\s*```/i)?.[1]?.trim();\n  const json_text = fenced ?? text.match(/\\{[\\s\\S]*\\}/)?.[0] ?? text;\n  return parsePrettified(CharacterExtractionResponse, JSON.parse(json_text)).characters;\n}\n\nasync function summarizeMessageWithStructuredOutput(\n  settings: AiSettings,\n  content: string,\n  options: SummaryGenerationOptions = {},\n): Promise<SummaryGenerationResult> {\n  const custom_source = settings.use_tavern_api ? undefined : inferCustomApiSource(settings);\n  console.info('[CosmosMemory] 使用结构化输出请求剧情总结', {\n    custom_source,\n    mode: custom_source === DEEPSEEK_API_SOURCE ? 'deepseek_json_object_via_st' : 'json_schema',\n    characters_enabled: options.characters_enabled === true,\n    items_enabled: options.items_enabled === true,\n    time_enabled: options.time_enabled === true,\n  });\n\n  const result = await window.TavernHelper.generateRaw({\n    should_silence: true,\n    custom_api: buildCustomApi(settings),\n    ordered_prompts: [\n      {\n        role: 'system',\n        content: buildSummarySystemPrompt(options),\n      },\n      {\n        role: 'user',\n        content: `请总结以下剧情内容：\\n\\n${buildSummaryContent(content, options)}`,\n      },\n    ],\n    json_schema: buildStructuredSummarySchema(options),\n  });\n\n  if (typeof result !== 'string') {\n    throw new Error('总结请求返回了非文本结果。');\n  }\n\n  return parseSummaryJson(result, options);\n}\n\nasync function summarizeMessageWithJsonPrompt(\n  settings: AiSettings,\n  content: string,\n  options: SummaryGenerationOptions = {},\n): Promise<SummaryGenerationResult> {\n  const result = await window.TavernHelper.generateRaw({\n    should_silence: true,\n    custom_api: buildCustomApi(settings),\n    ordered_prompts: [\n      {\n        role: 'system',\n        content: buildSummarySystemPrompt(options),\n      },\n      {\n        role: 'user',\n        content: `${buildSummaryJsonInstruction(options)}\\n\\n${buildSummaryContent(content, options)}`,\n      },\n    ],\n  });\n\n  if (typeof result !== 'string') {\n    throw new Error('总结请求返回了非文本结果。');\n  }\n\n  return parseSummaryJson(result, options);\n}\n\nexport async function summarizeMessage(\n  settings: AiSettings,\n  content: string,\n  options: SummaryGenerationOptions = {},\n): Promise<SummaryGenerationResult> {\n  try {\n    return await summarizeMessageWithStructuredOutput(settings, content, options);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    console.warn('[CosmosMemory] 结构化输出总结请求失败，降级为普通 JSON 提示重试', { message });\n    return summarizeMessageWithJsonPrompt(settings, content, options);\n  }\n}\n\nasync function extractCharactersWithStructuredOutput(\n  settings: AiSettings,\n  content: string,\n): Promise<StoredCharacter[]> {\n  const result = await window.TavernHelper.generateRaw({\n    should_silence: true,\n    custom_api: buildCustomApi(settings),\n    ordered_prompts: [\n      {\n        role: 'system',\n        content: FULL_CHARACTER_EXTRACTION_SYSTEM_PROMPT,\n      },\n      {\n        role: 'user',\n        content: `${FULL_CHARACTER_JSON_INSTRUCTION}\\n\\n${content}`,\n      },\n    ],\n    json_schema: buildFullCharacterExtractionSchema(),\n  });\n\n  if (typeof result !== 'string') {\n    throw new Error('人物信息重新生成返回了非文本结果。');\n  }\n\n  return parseFullCharacterExtractionJson(result);\n}\n\nasync function extractCharactersWithJsonPrompt(settings: AiSettings, content: string): Promise<StoredCharacter[]> {\n  const result = await window.TavernHelper.generateRaw({\n    should_silence: true,\n    custom_api: buildCustomApi(settings),\n    ordered_prompts: [\n      {\n        rol